   232→             << (isa<AllocaInst>(AllocaPtr) ? "Alloca " : "ByValArgument ")
   233→             << *AllocaPtr << "
"
   234→             << "            Access " << *Addr << "
"
   235→             << "            SCEV " << *Expr
   236→             << " U: " << SE.getUnsignedRange(Expr)
   237→             << ", S: " << SE.getSignedRange(Expr) << "
"
   238→             << "            Range " << AccessRange << "
"
   239→             << "            AllocaRange " << AllocaRange << "
"
   240→             << "            " << (Safe ? "safe" : "unsafe") << "
");
   241→
   242→  return Safe;
