    59→public:
    60→  struct InfoTy;
    61→
    62→private:
    63→  Module *M = nullptr;
    64→  std::function<const StackSafetyInfo &(Function &F)> GetSSI;
    65→  const ModuleSummaryIndex *Index = nullptr;
    66→  mutable std::unique_ptr<InfoTy> Info;
    67→  const InfoTy &getInfo() const;
